#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i = get_local_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    for (j = i; j < BLOCK_SIZE; j++) {
        float sum = 0.0f;
        for (k = 0; k < i; k++) {
            sum += AA(i,k) * AA(k,j);
        }
        AA(i,j) = AA(i,j) - sum;
    }

    if (i < BLOCK_SIZE - 1) {
        float temp_val = 1.0f / AA(i,i);
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += AA(j,k) * AA(k,i);
            }
            AA(j,i) = (AA(j,i) - sum) * temp_val;
        }
    }
}

kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_diag, const int size, const int offset)
{
    int idx = get_local_id(0);
    int chunk_idx = get_group_id(0);
    int chunks_in_inter_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (idx >= BLOCK_SIZE * 2) return;

    int i, j, k;
    int i_global, j_global;
    float sum;

    if (idx < BLOCK_SIZE) {
        i = idx;
        j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_diag[i * BLOCK_SIZE + j] = a[size * (i + offset) + offset + j];
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += temp_diag[BLOCK_SIZE * i + k] * BB(offset + k, j_global + j);
            }
            BB(offset + i, j_global + j) = BB(offset + i, j_global + j) - sum;
        }
    } else {
        i = idx - BLOCK_SIZE;
        i_global = offset + BLOCK_SIZE * (chunk_idx + 1);

        for (j = 0; j < BLOCK_SIZE; j++) {
            temp_diag[i * BLOCK_SIZE + j] = a[size * (offset + j) + offset + i];
        }

        for (j = 0; j < BLOCK_SIZE; j++) {
            sum = 0.0f;
            for (k = 0; k < j; k++) {
                sum += BB(i_global + i, offset + k) * temp_diag[BLOCK_SIZE * k + j];
            }
            a[size * (i_global + i) + offset + j] = (a[size * (i_global + i) + offset + j] - sum) / a[size * (offset + j) + offset + j];
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int i = get_local_id(0);
    int j = get_local_id(1);
    int chunk_idx_x = get_group_id(0);
    int chunk_idx_y = get_group_id(1);
    int chunks_in_inter_row = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (i >= BLOCK_SIZE || j >= BLOCK_SIZE) return;

    int i_global = offset + BLOCK_SIZE * (1 + chunk_idx_y);
    int j_global = offset + BLOCK_SIZE * (1 + chunk_idx_x);

    int k;
    float sum = 0.0f;

    for (k = 0; k < BLOCK_SIZE; k++) {
        temp_top[i * BLOCK_SIZE + k] = a[size * (i + offset) + j_global + k];
        temp_left[i * BLOCK_SIZE + k] = a[size * (i_global + i) + offset + k];
    }

    for (k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[BLOCK_SIZE * i + k] * temp_top[BLOCK_SIZE * k + j];
    }

    BB(i_global + i, j_global + j) -= sum;
}
